func:
// 1. Inicializa ou recupera contadores persistentes
let stats = context.get('stats') || { 
    total: 0, 
    sucessos: 0, 
    falhas: 0, 
    estado: "IDLE" 
};

const log = msg.payload.toString();

// 2. Regras de interpretação (Regex ou Includes)
if (log.includes("programa em execução")) {
    stats.estado = "EXECUTANDO";
} 
else if (log.includes("programa em home")) {
    stats.estado = "HOME";
} 
else if (log.includes("esteira 1 em execução")) {
    stats.estado = "ESTEIRA_ATIVA";
}

// 3. Lógica de Contagem de Peças/Ciclos
// Ajuste os termos abaixo conforme o log real do seu robô
if (log.includes("Ciclo concluído") || log.includes("Peça processada")) {
    stats.total++;
    stats.sucessos++;
} else if (log.includes("Erro") || log.includes("Falha")) {
    stats.total++;
    stats.falhas++;
    stats.estado = "ERRO";
}

// 4. Cálculo da Taxa de Acerto
let taxa = stats.total > 0 ? (stats.sucessos / stats.total) * 100 : 0;

// 5. Salva o progresso no contexto do nó
context.set('stats', stats);

// 6. Prepara o Payload para o Backend Node.js
msg.payload = {
    status_robo: stats.estado,
    total_pecas: stats.sucessos,
    total_ciclos: stats.total,
    taxa_acerto: taxa.toFixed(1) + "%",
    ultimo_log: log
};

return msg;
